type UpdateCurtailmentEventStateParams struct {
	State         string
	StartedAt     sql.NullTime
	EndedAt       sql.NullTime
	ID            int64
	ExpectedState string
}

// Row-count return is the race-loss guard; expected_state prevents stale
// phase writes (e.g. pending→active after Stop moved the event to restoring).
// nil narg preserves timestamps via COALESCE.
func (q *Queries) UpdateCurtailmentEventState(ctx context.Context, arg UpdateCurtailmentEventStateParams) (int64, error) {
	result, err := q.exec(ctx, q.updateCurtailmentEventStateStmt, updateCurtailmentEventState,
		arg.State,
		arg.StartedAt,
		arg.EndedAt,
		arg.ID,
		arg.ExpectedState,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected()
}

const updateCurtailmentTargetState = `-- name: UpdateCurtailmentTargetState :execrows
WITH locked_event AS MATERIALIZED (
    SELECT id
    FROM curtailment_event
    WHERE id = $11
        AND state IN ('pending', 'active', 'restoring')
        AND ($12::TEXT IS NULL
             OR state = $12::TEXT)
    FOR UPDATE
)
UPDATE curtailment_target
SET state              = $1,
    last_dispatched_at = COALESCE($2, last_dispatched_at),
    last_batch_uuid    = COALESCE($3,    last_batch_uuid),
    observed_power_w   = COALESCE($4,   observed_power_w),
    observed_at        = COALESCE($5,        observed_at),
    confirmed_at       = COALESCE($6,       confirmed_at),
    retry_count        = COALESCE($7,        retry_count),
    last_error         = CASE
        WHEN $8::text IS NULL THEN last_error
        ELSE NULLIF($8::text, '')
    END,
    curtail_state = CASE
        WHEN desired_state = 'curtailed' THEN $1
        ELSE curtail_state
    END,
    curtail_dispatched_at = CASE
        WHEN desired_state = 'curtailed' THEN COALESCE($2, curtail_dispatched_at)
        ELSE curtail_dispatched_at
    END,
    curtail_batch_uuid = CASE
        WHEN desired_state = 'curtailed' THEN COALESCE($3, curtail_batch_uuid)
        ELSE curtail_batch_uuid
    END,
    curtail_completed_at = CASE
        WHEN desired_state = 'curtailed'
             AND $1 IN ('confirmed', 'released', 'restore_failed') THEN
            COALESCE($6, CURRENT_TIMESTAMP)
        ELSE curtail_completed_at
    END,
    curtail_retry_count = CASE
        WHEN desired_state = 'curtailed' THEN COALESCE($7, curtail_retry_count)
        ELSE curtail_retry_count
    END,
    curtail_failure_count = CASE
        WHEN desired_state = 'curtailed'
             AND NULLIF($8::text, '') IS NOT NULL THEN curtail_failure_count + 1
        ELSE curtail_failure_count
    END,
    curtail_last_error = CASE
        WHEN desired_state = 'curtailed'
             AND NULLIF($8::text, '') IS NOT NULL THEN NULLIF($8::text, '')
        ELSE curtail_last_error
    END,
    restore_state = CASE
        WHEN desired_state = 'active' THEN $1
        ELSE restore_state
    END,
    restore_dispatched_at = CASE
        WHEN desired_state = 'active' THEN COALESCE($2, restore_dispatched_at)
        ELSE restore_dispatched_at
    END,
    restore_batch_uuid = CASE
        WHEN desired_state = 'active' THEN COALESCE($3, restore_batch_uuid)
        ELSE restore_batch_uuid
    END,
    restore_completed_at = CASE
        WHEN desired_state = 'active'
             AND $1 IN ('resolved', 'released', 'restore_failed') THEN
            COALESCE($6, CURRENT_TIMESTAMP)
        ELSE restore_completed_at
    END,
    restore_retry_count = CASE
        WHEN desired_state = 'active' THEN COALESCE($7, restore_retry_count)
        ELSE restore_retry_count
    END,
    restore_failure_count = CASE
        WHEN desired_state = 'active'
             AND NULLIF($8::text, '') IS NOT NULL THEN restore_failure_count + 1
        ELSE restore_failure_count
    END,
    restore_last_error = CASE
        WHEN desired_state = 'active'
             AND NULLIF($8::text, '') IS NOT NULL THEN NULLIF($8::text, '')
        ELSE restore_last_error
    END
FROM locked_event
WHERE curtailment_event_id = locked_event.id
  AND device_identifier    = $9
  AND ($10::text IS NULL
       OR desired_state = $10::text)
`

type UpdateCurtailmentTargetStateParams struct {
	State                string
	LastDispatchedAt     sql.NullTime
	LastBatchUuid        sql.NullString
	ObservedPowerW       sql.NullString
	ObservedAt           sql.NullTime
	ConfirmedAt          sql.NullTime
	RetryCount           sql.NullInt32
	LastError            sql.NullString
	DeviceIdentifier     string
	ExpectedDesiredState sql.NullString
	CurtailmentEventID   int64
	ExpectedEventState   sql.NullString
}

// Reconciler patch. COALESCE preserves un-supplied columns; empty
// last_error is the explicit clear sentinel that maps to SQL NULL.
//
// Parent event row is locked before the target update so Stop/AdminTerminate
// and target claims serialize on the event lifecycle. expected_event_state
// maps stale phase writes to ErrCurtailmentEventStateRaceLoss.
//
// expected_desired_state scopes the write to one dispatch direction so
// a concurrent Stop's reset isn't clobbered by a Curtail-phase post-cmd
// write (observeRestoring picks up the reset target afterwards).
func (q *Queries) UpdateCurtailmentTargetState(ctx context.Context, arg UpdateCurtailmentTargetStateParams) (int64, error) {
	result, err := q.exec(ctx, q.updateCurtailmentTargetStateStmt, updateCurtailmentTargetState,
		arg.State,
		arg.LastDispatchedAt,
		arg.LastBatchUuid,
		arg.ObservedPowerW,
		arg.ObservedAt,
		arg.ConfirmedAt,
		arg.RetryCount,
		arg.LastError,
		arg.DeviceIdentifier,
		arg.ExpectedDesiredState,
		arg.CurtailmentEventID,
		arg.ExpectedEventState,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected()
}

